import threading
import time
import uuid
import hashlib

class TransactionError(Exception):
    pass

class InsufficientFundsError(TransactionError):
    pass

class AccountNotFoundError(TransactionError):
    pass

class InvalidAmountError(TransactionError):
    pass

class TransactionConflictError(TransactionError):
    pass

class FraudDetectedError(TransactionError):
    pass

class Account:
    def __init__(self, account_id, balance, owner_id):
        self.account_id = account_id
        self.balance = balance
        self.owner_id = owner_id
        self.lock = threading.Lock()

    def deposit(self, amount):
        if amount <= 0:
            raise InvalidAmountError("Deposit amount must be positive.")
        with self.lock:
            self.balance += amount
            return self.balance

    def withdraw(self, amount):
        if amount <= 0:
            raise InvalidAmountError("Withdrawal amount must be positive.")
        with self.lock:
            if self.balance < amount:
                raise InsufficientFundsError("Insufficient funds.")
            self.balance -= amount
            return self.balance

    def get_balance(self):
        with self.lock:
            return self.balance

class Transaction:
    def __init__(self, transaction_id, from_account_id, to_account_id, amount, timestamp, status="PENDING", description=None):
        self.transaction_id = transaction_id
        self.from_account_id = from_account_id
        self.to_account_id = to_account_id
        self.amount = amount
        self.timestamp = timestamp
        self.status = status
        self.description = description

    def __repr__(self):
        return f"Transaction(id={self.transaction_id}, from={self.from_account_id}, to={self.to_account_id}, amount={self.amount}, status={self.status})"

class Comptroller:
    def __init__(self):
        self.accounts = {}
        self.transactions = {}
        self.transaction_lock = threading.Lock()
        self.fraud_detection_threshold = 10000  # Example threshold
        self.transaction_history_limit = 100 # Limit the number of transactions stored

    def create_account(self, owner_id, initial_balance=0):
        account_id = str(uuid.uuid4())
        account = Account(account_id, initial_balance, owner_id)
        self.accounts[account_id] = account
        return account_id

    def get_account(self, account_id):
        if account_id not in self.accounts:
            raise AccountNotFoundError(f"Account with ID {account_id} not found.")
        return self.accounts[account_id]

    def _record_transaction(self, transaction):
        with self.transaction_lock:
            self.transactions[transaction.transaction_id] = transaction
            # Maintain transaction history limit
            if len(self.transactions) > self.transaction_history_limit:
                # Remove the oldest transaction (simplistic approach)
                oldest_transaction_id = min(self.transactions.keys())
                del self.transactions[oldest_transaction_id]

    def _is_fraudulent(self, amount):
        # Simple fraud detection: check if amount exceeds threshold
        return amount > self.fraud_detection_threshold

    def transfer_funds(self, from_account_id, to_account_id, amount, description=None):
        if amount <= 0:
            raise InvalidAmountError("Transfer amount must be positive.")

        if from_account_id == to_account_id:
            raise InvalidAmountError("Cannot transfer to the same account.")

        from_account = self.get_account(from_account_id)
        to_account = self.get_account(to_account_id)

        if self._is_fraudulent(amount):
            raise FraudDetectedError(f"Potential fraud detected: Transfer amount {amount} exceeds threshold.")

        transaction_id = str(uuid.uuid4())
        timestamp = time.time()
        transaction = Transaction(transaction_id, from_account_id, to_account_id, amount, timestamp, description=description)

        try:
            # Lock both accounts to prevent race conditions.  Order is important to prevent deadlocks.
            if from_account_id < to_account_id:
                lock1, lock2 = from_account.lock, to_account.lock
            else:
                lock1, lock2 = to_account.lock, from_account.lock

            with lock1:
                with lock2:
                    from_account.withdraw(amount)
                    to_account.deposit(amount)
                    transaction.status = "COMPLETED"
                    self._record_transaction(transaction)
                    return transaction_id
        except InsufficientFundsError as e:
            transaction.status = "FAILED"
            self._record_transaction(transaction)
            raise e
        except Exception as e:
            transaction.status = "FAILED"
            self._record_transaction(transaction)
            raise TransactionError(f"Transaction failed: {e}")

    def get_transaction_status(self, transaction_id):
        with self.transaction_lock:
            if transaction_id not in self.transactions:
                return "NOT FOUND"
            return self.transactions[transaction_id].status

    def get_account_balance(self, account_id):
         account = self.get_account(account_id)
         return account.get_balance()

    def generate_audit_trail(self, account_id):
        """Generates a simplified audit trail for an account."""
        audit_trail = []
        with self.transaction_lock:
            for transaction_id, transaction in self.transactions.items():
                if transaction.from_account_id == account_id or transaction.to_account_id == account_id:
                    audit_trail.append(transaction)
        return audit_trail

    def hash_transaction(self, transaction_id):
        """Hashes a transaction for integrity verification."""
        with self.transaction_lock:
            if transaction_id not in self.transactions:
                return None
            transaction = self.transactions[transaction_id]
            transaction_string = f"{transaction.transaction_id}{transaction.from_account_id}{transaction.to_account_id}{transaction.amount}{transaction.timestamp}{transaction.status}"
            return hashlib.sha256(transaction_string.encode()).hexdigest()

