import threading
import time
import uuid
import hashlib
import hmac
import secrets
import logging
from collections import deque

logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

class ATM:
    def __init__(self, atm_id, initial_balance=0):
        self.atm_id = atm_id
        self.balance = initial_balance
        self.lock = threading.Lock()
        self.transaction_log = deque(maxlen=100)  # Keep a limited history
        self.secret_key = secrets.token_bytes(32) # Unique secret key for each ATM
        logging.info(f"ATM {self.atm_id} initialized with balance {self.balance}")

    def deposit(self, amount, transaction_id):
        with self.lock:
            if amount > 0 and self.is_unique_transaction(transaction_id):
                self.balance += amount
                self.log_transaction(transaction_id, "deposit", amount)
                logging.info(f"ATM {self.atm_id}: Deposited {amount}. New balance: {self.balance}")
                return True
            else:
                logging.warning(f"ATM {self.atm_id}: Invalid deposit amount or duplicate transaction {transaction_id}")
                return False

    def withdraw(self, amount, transaction_id):
        with self.lock:
            if amount > 0 and self.balance >= amount and self.is_unique_transaction(transaction_id):
                self.balance -= amount
                self.log_transaction(transaction_id, "withdraw", amount)
                logging.info(f"ATM {self.atm_id}: Withdrew {amount}. New balance: {self.balance}")
                return True
            else:
                logging.warning(f"ATM {self.atm_id}: Invalid withdrawal amount, insufficient funds, or duplicate transaction {transaction_id}")
                return False

    def get_balance(self):
        with self.lock:
            return self.balance

    def log_transaction(self, transaction_id, transaction_type, amount):
        timestamp = time.time()
        transaction_data = {
            "transaction_id": transaction_id,
            "type": transaction_type,
            "amount": amount,
            "timestamp": timestamp
        }
        self.transaction_log.append(transaction_data)

    def is_unique_transaction(self, transaction_id):
        for transaction in self.transaction_log:
            if transaction["transaction_id"] == transaction_id:
                return False
        return True

    def generate_hmac(self, data):
        """Generates an HMAC for data integrity."""
        return hmac.new(self.secret_key, data.encode('utf-8'), hashlib.sha256).hexdigest()

    def verify_hmac(self, data, hmac_value):
        """Verifies the HMAC to ensure data integrity."""
        expected_hmac = self.generate_hmac(data)
        return hmac.compare_digest(expected_hmac, hmac_value)

class ATMController:
    def __init__(self):
        self.atms = {}
        self.atm_locks = {} # Lock per ATM to prevent concurrent operations on the same ATM
        self.global_lock = threading.Lock() # Global lock for managing ATM list
        self.transaction_coordinator = TransactionCoordinator(self)

    def create_atm(self, atm_id, initial_balance=0):
        with self.global_lock:
            if atm_id not in self.atms:
                self.atms[atm_id] = ATM(atm_id, initial_balance)
                self.atm_locks[atm_id] = threading.Lock()
                logging.info(f"ATM {atm_id} created.")
                return True
            else:
                logging.warning(f"ATM {atm_id} already exists.")
                return False

    def get_atm(self, atm_id):
        with self.global_lock:
            return self.atms.get(atm_id)

    def transfer_funds(self, from_atm_id, to_atm_id, amount, transaction_id):
        return self.transaction_coordinator.transfer_funds(from_atm_id, to_atm_id, amount, transaction_id)

    def get_balance(self, atm_id):
        atm = self.get_atm(atm_id)
        if atm:
            return atm.get_balance()
        else:
            logging.error(f"ATM {atm_id} not found.")
            return None

    def perform_operation(self, atm_id, operation, amount, transaction_id):
        atm = self.get_atm(atm_id)
        if not atm:
            logging.error(f"ATM {atm_id} not found.")
            return False

        with self.atm_locks[atm_id]: # Lock specific ATM
            if operation == "deposit":
                return atm.deposit(amount, transaction_id)
            elif operation == "withdraw":
                return atm.withdraw(amount, transaction_id)
            else:
                logging.warning(f"Invalid operation: {operation}")
                return False

class TransactionCoordinator:
    def __init__(self, atm_controller):
        self.atm_controller = atm_controller
        self.transaction_locks = {} # Lock per transaction to prevent race conditions

    def transfer_funds(self, from_atm_id, to_atm_id, amount, transaction_id):
        """
        Atomically transfers funds from one ATM to another.  Uses a transaction lock
        to prevent race conditions and ensures that the transfer is all or nothing.
        """
        if from_atm_id == to_atm_id:
            logging.warning("Cannot transfer funds to the same ATM.")
            return False

        if transaction_id in self.transaction_locks:
            logging.warning(f"Transaction {transaction_id} already in progress.")
            return False

        self.transaction_locks[transaction_id] = threading.Lock()

        try:
            with self.transaction_locks[transaction_id]:
                from_atm = self.atm_controller.get_atm(from_atm_id)
                to_atm = self.atm_controller.get_atm(to_atm_id)

                if not from_atm or not to_atm:
                    logging.error("One or both ATMs not found.")
                    return False

                # Withdraw from the source ATM
                if not self.atm_controller.perform_operation(from_atm_id, "withdraw", amount, transaction_id):
                    logging.error(f"Failed to withdraw {amount} from ATM {from_atm_id}")
                    return False

                # Deposit into the destination ATM
                if not self.atm_controller.perform_operation(to_atm_id, "deposit", amount, transaction_id):
                    logging.error(f"Failed to deposit {amount} into ATM {to_atm_id}.  Reverting withdrawal.")
                    # Attempt to revert the withdrawal.  If this fails, manual intervention is required.
                    if not self.atm_controller.perform_operation(from_atm_id, "deposit", amount, str(uuid.uuid4())): # New transaction ID for revert
                        logging.critical(f"CRITICAL: Failed to revert withdrawal from ATM {from_atm_id}. Manual intervention required.")
                    return False

                logging.info(f"Successfully transferred {amount} from ATM {from_atm_id} to ATM {to_atm_id}")
                return True

        finally:
            del self.transaction_locks[transaction_id] # Release the lock

