        with self.lock:
            if amount <= 0:
                print(f"ATM {self.atm_id}: Invalid transfer amount.")
                return False

            if self.balance < amount:
                print(f"ATM {self.atm_id}: Insufficient funds for transfer.")
                return False

            if not target_atm:
                print(f"ATM {self.atm_id}: Invalid target ATM.")
                return False

            # Attempt to withdraw from this ATM
            if self.withdraw(amount, from_account_id):
                # Attempt to deposit into the target ATM
                if target_atm.deposit(amount, to_account_id):
                    self.transaction_log.append({
                        "transaction_type": "transfer_out",
                        "account_id": from_account_id,
                        "target_account_id": to_account_id,
                        "amount": amount,
                        "timestamp": time.time(),
                        "atm_id": self.atm_id,
                        "new_balance": self.balance
                    })
                    return True
                else:
                    # If deposit fails, rollback the withdrawal
                    self.deposit(amount, from_account_id)
                    print(f"ATM {self.atm_id}: Transfer failed. Rolling back withdrawal.")
                    return False
            else:
                print(f"ATM {self.atm_id}: Withdrawal failed for transfer.")
                return False

    def audit_transaction_log(self):
        with self.lock:
            print(f"ATM {self.atm_id}: Transaction Log:")
