class SecurityModule:
    def __init__(self):
        self.suspicious_activity = {} #account_id: [timestamps]
        self.threshold = 3 # Number of transactions within a time window to flag as suspicious
        self.time_window = 60 # Time window in seconds

    def authenticate_transaction(self, account_id, amount, transaction_type):
        # Simulate security checks (e.g., fraud detection, rate limiting)
