            print(f"Security Alert: Suspicious activity detected for account {account_id}. Transaction blocked.")
            return False

        if self.is_fraudulent(amount, transaction_type):
            print("Security Alert: Potential fraudulent transaction detected. Transaction blocked.")
            return False

        self.log_activity(account_id)
        return True

    def is_suspicious(self, account_id):
        current_time = time.time()
        if account_id in self.suspicious_activity:
            timestamps = self.suspicious_activity[account_id]
            # Filter timestamps within the time window
            recent_timestamps = [t for t in timestamps if current_time - t <= self.time_window]
            self.suspicious_activity[account_id] = recent_timestamps #update the timestamps
            if len(recent_timestamps) >= self.threshold:
                return True
        return False

    def log_activity(self, account_id):
        current_time = time.time()
        if account_id in self.suspicious_activity:
            self.suspicious_activity[account_id].append(current_time)
        else:
            self.suspicious_activity[account_id] = [current_time]

    def is_fraudulent(self, amount, transaction_type):
