import threading
import time
import uuid
import hashlib
import hmac
import secrets
import logging

# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

class Transaction:
    def __init__(self, sender_id, receiver_id, amount, transaction_type="transfer"):
        self.sender_id = sender_id
        self.receiver_id = receiver_id
        self.amount = amount
        self.transaction_type = transaction_type  # e.g., "transfer", "deposit", "withdrawal"
        self.transaction_id = uuid.uuid4()
        self.timestamp = time.time()
        self.status = "pending"  # pending, completed, failed
        self.signature = None

    def sign_transaction(self, secret_key):
        """Signs the transaction using HMAC."""
        message = f"{self.sender_id}{self.receiver_id}{self.amount}{self.transaction_type}{self.transaction_id}{self.timestamp}".encode('utf-8')
        self.signature = hmac.new(secret_key.encode('utf-8'), message, hashlib.sha256).hexdigest()

    def verify_signature(self, secret_key):
        """Verifies the transaction signature."""
        message = f"{self.sender_id}{self.receiver_id}{self.amount}{self.transaction_type}{self.transaction_id}{self.timestamp}".encode('utf-8')
        expected_signature = hmac.new(secret_key.encode('utf-8'), message, hashlib.sha256).hexdigest()
        return hmac.compare_digest(self.signature, expected_signature)

    def __repr__(self):
        return f"Transaction(ID: {self.transaction_id}, Sender: {self.sender_id}, Receiver: {self.receiver_id}, Amount: {self.amount}, Status: {self.status})"


class Account:
    def __init__(self, account_id, initial_balance=0):
        self.account_id = account_id
        self.balance = initial_balance
        self.lock = threading.Lock()  # Lock for thread-safe balance updates

    def deposit(self, amount):
        with self.lock:
            self.balance += amount
            return True

    def withdraw(self, amount):
        with self.lock:
            if self.balance >= amount:
                self.balance -= amount
                return True
            else:
                return False

    def get_balance(self):
        with self.lock:
            return self.balance

class RestrainerOrganization:
    def __init__(self):
        self.accounts = {}
        self.transactions = {}
        self.transaction_log = []
        self.lock = threading.Lock()  # Global lock for critical operations
        self.secret_keys = {} # Store secret keys for each account

    def create_account(self, account_id, initial_balance=0):
        with self.lock:
            if account_id not in self.accounts:
                self.accounts[account_id] = Account(account_id, initial_balance)
                self.secret_keys[account_id] = secrets.token_hex(32) # Generate a secure random key
                logging.info(f"Account {account_id} created with initial balance {initial_balance}")
                return True
            else:
                logging.warning(f"Account {account_id} already exists.")
                return False

    def get_account(self, account_id):
        with self.lock:
            return self.accounts.get(account_id)

    def generate_transaction(self, sender_id, receiver_id, amount, transaction_type="transfer"):
        """Generates a transaction object and signs it."""
        transaction = Transaction(sender_id, receiver_id, amount, transaction_type)
        sender_secret_key = self.secret_keys.get(sender_id)
        if not sender_secret_key:
            logging.error(f"Sender {sender_id} has no secret key.")
            return None
        transaction.sign_transaction(sender_secret_key)
        return transaction

    def submit_transaction(self, transaction):
        with self.lock:
            if transaction.transaction_id in self.transactions:
                logging.warning(f"Transaction {transaction.transaction_id} already exists.")
                return False

            sender_secret_key = self.secret_keys.get(transaction.sender_id)
            if not sender_secret_key:
                logging.error(f"Sender {transaction.sender_id} has no secret key.")
                return False

            if not transaction.verify_signature(sender_secret_key):
                logging.error(f"Invalid signature for transaction {transaction.transaction_id}")
                return False

            self.transactions[transaction.transaction_id] = transaction
            self.transaction_log.append(transaction)
            logging.info(f"Transaction {transaction.transaction_id} submitted.")
            return True

    def process_transaction(self, transaction_id):
        transaction = self.transactions.get(transaction_id)
        if not transaction:
            logging.error(f"Transaction {transaction_id} not found.")
            return False

        if transaction.status != "pending":
            logging.warning(f"Transaction {transaction_id} is not in pending state.")
            return False

        sender = self.get_account(transaction.sender_id)
        receiver = self.get_account(transaction.receiver_id)

        if not sender or not receiver:
            logging.error(f"Invalid sender or receiver account for transaction {transaction_id}")
            transaction.status = "failed"
            return False

        if transaction.transaction_type == "transfer":
            if sender.withdraw(transaction.amount):
                receiver.deposit(transaction.amount)
                transaction.status = "completed"
                logging.info(f"Transaction {transaction_id} completed successfully.")
                return True
            else:
                transaction.status = "failed"
                logging.error(f"Transaction {transaction_id} failed due to insufficient balance.")
                return False
        elif transaction.transaction_type == "deposit":
            receiver.deposit(transaction.amount)
            transaction.status = "completed"
            logging.info(f"Deposit transaction {transaction_id} completed successfully.")
            return True
        elif transaction.transaction_type == "withdrawal":
            if sender.withdraw(transaction.amount):
                transaction.status = "completed"
                logging.info(f"Withdrawal transaction {transaction_id} completed successfully.")
                return True
            else:
                transaction.status = "failed"
                logging.error(f"Withdrawal transaction {transaction_id} failed due to insufficient balance.")
                return False
        else:
            transaction.status = "failed"
            logging.error(f"Unknown transaction type for transaction {transaction_id}")
            return False

    def get_transaction_status(self, transaction_id):
        transaction = self.transactions.get(transaction_id)
        if transaction:
            return transaction.status
        else:
            return None

    def audit_transaction_log(self):
        """Performs an audit of the transaction log to ensure consistency."""
        total_deposits = 0
        total_withdrawals = 0
        total_transfers = 0
        failed_transactions = 0

        for transaction in self.transaction_log:
            if transaction.status == "completed":
                if transaction.transaction_type == "deposit":
                    total_deposits += transaction.amount
                elif transaction.transaction_type == "withdrawal":
                    total_withdrawals += transaction.amount
                elif transaction.transaction_type == "transfer":
                    total_transfers += transaction.amount
            elif transaction.status == "failed":
                failed_transactions += 1

        logging.info(f"Audit Report: Total Deposits: {total_deposits}, Total Withdrawals: {total_withdrawals}, Total Transfers: {total_transfers}, Failed Transactions: {failed_transactions}")

    def run_integrity_check(self):
        """Checks the integrity of account balances against transaction history."""
        balance_mismatch = False
        for account_id, account in self.accounts.items():
            expected_balance = 0
            for transaction in self.transaction_log:
                if transaction.status == "completed":
                    if transaction.receiver_id == account_id:
                        expected_balance += transaction.amount
                    if transaction.sender_id == account_id:
                        expected_balance -= transaction.amount
            if round(account.get_balance(), 2) != round(account.balance, 2):
                logging.error(f"Balance mismatch detected for account {account_id}. Expected: {expected_balance}, Actual: {account.get_balance()}")
                balance_mismatch = True

        if not balance_mismatch:
            logging.info("Integrity check passed: Account balances are consistent with transaction history.")
        else:
            logging.warning("Integrity check failed: Balance mismatches detected.")

