import threading
import time
import random
import hashlib

class Account:
    def __init__(self, account_number, balance, pin):
        self.account_number = account_number
        self.balance = balance
        self.pin_hash = hashlib.sha256(str(pin).encode()).hexdigest()  # Store PIN as a hash
        self.lock = threading.Lock()

    def verify_pin(self, pin):
        return hashlib.sha256(str(pin).encode()).hexdigest() == self.pin_hash

    def deposit(self, amount):
        with self.lock:
            self.balance += amount
            return True

    def withdraw(self, amount):
        with self.lock:
            if self.balance >= amount:
                self.balance -= amount
                return True
            else:
                return False

    def get_balance(self):
        with self.lock:
            return self.balance

class Transaction:
    def __init__(self, account_number, transaction_type, amount, timestamp):
        self.account_number = account_number
        self.transaction_type = transaction_type
        self.amount = amount
        self.timestamp = timestamp

    def __str__(self):
        return f"Account: {self.account_number}, Type: {self.transaction_type}, Amount: {self.amount}, Time: {self.timestamp}"

class TransactionLog:
    def __init__(self):
        self.transactions = []
        self.lock = threading.Lock()

    def log_transaction(self, transaction):
        with self.lock:
            self.transactions.append(transaction)

    def get_transactions_for_account(self, account_number):
        with self.lock:
            return [t for t in self.transactions if t.account_number == account_number]

class ATM:
    def __init__(self, atm_id, account_manager, transaction_log):
        self.atm_id = atm_id
        self.account_manager = account_manager
        self.transaction_log = transaction_log

    def perform_transaction(self, account_number, pin, transaction_type, amount):
        account = self.account_manager.get_account(account_number)

        if not account:
            return False, "Invalid account number."

        if not account.verify_pin(pin):
            return False, "Invalid PIN."

        if transaction_type == "deposit":
            success = account.deposit(amount)
            if success:
                self.transaction_log.log_transaction(Transaction(account_number, "deposit", amount, time.time()))
                return True, "Deposit successful."
            else:
                return False, "Deposit failed."
        elif transaction_type == "withdraw":
            success = account.withdraw(amount)
            if success:
                self.transaction_log.log_transaction(Transaction(account_number, "withdraw", amount, time.time()))
                return True, "Withdrawal successful."
            else:
                return False, "Insufficient funds."
        elif transaction_type == "balance":
            balance = account.get_balance()
            return True, f"Current balance: {balance}"
        else:
            return False, "Invalid transaction type."

class AccountManager:
    def __init__(self):
        self.accounts = {}
        self.lock = threading.Lock()

    def create_account(self, account_number, initial_balance, pin):
        with self.lock:
            if account_number in self.accounts:
                return False, "Account already exists."
            self.accounts[account_number] = Account(account_number, initial_balance, pin)
            return True, "Account created successfully."

    def get_account(self, account_number):
        with self.lock:
            return self.accounts.get(account_number)

    def transfer_funds(self, from_account_number, to_account_number, amount):
        from_account = self.get_account(from_account_number)
        to_account = self.get_account(to_account_number)

        if not from_account or not to_account:
            return False, "Invalid account number(s)."

        # Lock both accounts to prevent deadlock
        if from_account_number < to_account_number:
            lock1, lock2 = from_account.lock, to_account.lock
        else:
            lock1, lock2 = to_account.lock, from_account.lock

        with lock1:
            with lock2:
                if from_account.balance >= amount:
                    from_account.balance -= amount
                    to_account.balance += amount
                    return True, "Transfer successful."
                else:
                    return False, "Insufficient funds."

def simulate_atm_transaction(atm, account_number, pin, transaction_type, amount):
    success, message = atm.perform_transaction(account_number, pin, transaction_type, amount)
    print(f"ATM {atm.atm_id}: Account {account_number}, {transaction_type} {amount} - {message}")
    return success, message

