import time
import random
import hashlib

class ATM:
    def __init__(self, atm_id, initial_balance=0):
        self.atm_id = atm_id
        self.balance = initial_balance
        self.lock = threading.Lock()
        self.transaction_log = []  # Store transaction details for auditing
        self.is_online = True  # Simulate ATM availability

    def deposit(self, amount, transaction_id):
        with self.lock:
            if not self.is_online:
                return False, "ATM is currently offline."

            if amount <= 0:
                return False, "Invalid deposit amount."

            self.balance += amount
            self.transaction_log.append({
                "transaction_id": transaction_id,
                "type": "deposit",
                "amount": amount,
                "timestamp": time.time()
            })
            return True, f"Deposit successful. New balance: {self.balance}"

    def withdraw(self, amount, transaction_id):
        with self.lock:
            if not self.is_online:
                return False, "ATM is currently offline."

            if amount <= 0:
                return False, "Invalid withdrawal amount."

            if self.balance < amount:
                return False, "Insufficient funds."

            self.balance -= amount
            self.transaction_log.append({
                "transaction_id": transaction_id,
                "type": "withdrawal",
                "amount": amount,
                "timestamp": time.time()
            })
            return True, f"Withdrawal successful. New balance: {self.balance}"

    def get_balance(self):
        with self.lock:
            if not self.is_online:
                return False, "ATM is currently offline."
            return True, self.balance

    def set_offline(self):
        with self.lock:
            self.is_online = False

    def set_online(self):
        with self.lock:
            self.is_online = True

    def get_transaction_log(self):
        with self.lock:
            return self.transaction_log[:] # Return a copy to prevent external modification

class CentralBank:
    def __init__(self):
        self.atms = {}
        self.transaction_history = []
        self.lock = threading.Lock()
        self.transaction_id_counter = 0

    def register_atm(self, atm):
        with self.lock:
            if atm.atm_id not in self.atms:
                self.atms[atm.atm_id] = atm
                print(f"ATM {atm.atm_id} registered.")
            else:
                print(f"ATM {atm.atm_id} already registered.")

    def deregister_atm(self, atm_id):
        with self.lock:
            if atm_id in self.atms:
                del self.atms[atm_id]
                print(f"ATM {atm_id} deregistered.")
            else:
                print(f"ATM {atm_id} not found.")

    def perform_transaction(self, atm_id, transaction_type, amount):
        with self.lock:
            if atm_id not in self.atms:
                return False, "ATM not registered."

            atm = self.atms[atm_id]
            transaction_id = self.generate_transaction_id()

            if transaction_type == "deposit":
                success, message = atm.deposit(amount, transaction_id)
            elif transaction_type == "withdraw":
                success, message = atm.withdraw(amount, transaction_id)
            else:
                return False, "Invalid transaction type."

            if success:
                self.transaction_history.append({
                    "transaction_id": transaction_id,
                    "atm_id": atm_id,
                    "type": transaction_type,
                    "amount": amount,
                    "timestamp": time.time()
                })
            return success, message

    def get_balance(self, atm_id):
        with self.lock:
            if atm_id not in self.atms:
                return False, "ATM not registered."

            atm = self.atms[atm_id]
            return atm.get_balance()

    def audit_transactions(self):
        with self.lock:
            print("Transaction History:")
            for transaction in self.transaction_history:
                print(transaction)

    def generate_transaction_id(self):
        with self.lock:
            self.transaction_id_counter += 1
            return hashlib.sha256(str(self.transaction_id_counter).encode()).hexdigest()

    def simulate_network_partition(self, atm_id):
        with self.lock:
            if atm_id in self.atms:
                self.atms[atm_id].set_offline()
                print(f"Simulating network partition for ATM {atm_id}")
            else:
                print(f"ATM {atm_id} not found.")

    def resolve_network_partition(self, atm_id):
        with self.lock:
            if atm_id in self.atms:
                self.atms[atm_id].set_online()
                print(f"Resolving network partition for ATM {atm_id}")
            else:
                print(f"ATM {atm_id} not found.")

